import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return

    it = iter(data)
    n = int(next(it))
    m = int(next(it))

    edges = []
    for i in range(m):
        u = int(next(it))
        v = int(next(it))
        c = int(next(it))
        edges.append((u, v, c, i + 1))

    # Find a topological order
    # We'll use Kahn's algorithm for topological sorting
    # If there's a cycle, we'll need to break it

    # Build adjacency list
    adj = [[] for _ in range(n + 1)]
    in_degree = [0] * (n + 1)

    for u, v, c, idx in edges:
        adj[u].append((v, c, idx))
        in_degree[v] += 1

    # Kahn's algorithm
    queue = []
    for i in range(1, n + 1):
        if in_degree[i] == 0:
            queue.append(i)

    topo_order = []
    while queue:
        u = queue.pop(0)
        topo_order.append(u)
        for v, c, idx in adj[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                queue.append(v)

    # Create a dictionary to map nodes to their positions in the topological order
    # For nodes not in the topological order (part of a cycle), assign a large value
    node_pos = {}
    for i, node in enumerate(topo_order):
        node_pos[node] = i

    # For nodes not in the topological order, assign a position after all others
    for node in range(1, n + 1):
        if node not in node_pos:
            node_pos[node] = len(topo_order)

    # Find edges that go backwards in the topological order
    reversed_edges = []
    for u, v, c, idx in edges:
        if node_pos[u] > node_pos[v]:
            reversed_edges.append((u, v, c, idx))

    print(len(reversed_edges), len(reversed_edges))
    if reversed_edges:
        print(' '.join(str(idx) for _, _, _, idx in reversed_edges))

if __name__ == '__main__':
    solve()
